sql:
SELECT SUM(risk_value) AS total_risk_exposure
FROM risk_exposures
WHERE option_id = 0;

SELECT total_value, total_risk 
FROM portfolios 
WHERE portfolio_id = 0;

SELECT 
  (SELECT MAX(implied_volatility) FROM options) AS max_implied_volatility,
  (SELECT portfolio_name FROM portfolios ORDER BY total_value DESC LIMIT 1) AS portfolio_name;

SELECT 
  (SELECT COUNT(trade_id) FROM trades) AS total_trades,
  (SELECT SUM(total_value) FROM portfolios) AS total_portfolio_value;

SELECT strike_price 
FROM options 
WHERE bid_price = (SELECT MAX(bid_price) FROM options);

SELECT AVG(profit_loss) AS average_profit_loss
FROM positions
WHERE position_id = 0;

external_knowledge:
- 'yet to reach their expiration dates' refers to options with an expiration date greater than or equal to the most recent expiration date across all options;
- 'most recent trading day' refers to the most recent trade date across all trades;
- 'fully executed' refers to trades with a trade status of 'completed';
- 'default user' refers to the user with an ID of 0.

sql:
